func TestForLanguage_Supported(t *testing.T) {
	supported := []string{"go", "ts", "js", "py", "rs"}
	for _, lang := range supported {
		t.Run(lang, func(t *testing.T) {
			a := analysis.ForLanguage(lang)
			if a == nil {
				t.Errorf("ForLanguage(%q) returned nil, want non-nil analyzer", lang)
			}
		})
	}
}

func TestForLanguage_Unsupported(t *testing.T) {
	unsupported := []string{"swift", "brainfuck"}
	for _, lang := range unsupported {
		t.Run(lang, func(t *testing.T) {
			a := analysis.ForLanguage(lang)
			if a != nil {
				t.Errorf("ForLanguage(%q) returned non-nil, want nil for unsupported language", lang)
			}
		})
	}
}

func TestCertifier_UnsupportedLanguageYieldsNA(t *testing.T) {
	tmpDir := t.TempDir()
	src := `// swift placeholder
func greet() -> String {
    return "Hello"
}
`
	if err := os.WriteFile(filepath.Join(tmpDir, "greet.swift"), []byte(src), 0o644); err != nil {
		t.Fatal(err)
	}

	certifier := &engine.Certifier{
		Root:      tmpDir,
		ExpiryCfg: domain.ExpiryConfig{DefaultWindowDays: 90, MinWindowDays: 7, MaxWindowDays: 365},
	}

	unit := domain.NewUnit(
		domain.NewUnitID("swift", "greet.swift", "greet"),
		domain.UnitTypeFunction,
	)

	result, err := certifier.Certify(context.Background(), unit, nil, time.Now())
	if err != nil {
		t.Fatalf("Certify() error: %v", err)
	}
	if result == nil {
		t.Fatal("Certify() returned nil result")
	}

	if result.Record.Grade != domain.GradeNA {
		t.Errorf("Grade = %q, want %q (N/A) for unsupported language", result.Record.Grade, domain.GradeNA)
	}
	if result.Record.Score != 0.0 {
		t.Errorf("Score = %f, want 0.0 for unsupported language", result.Record.Score)
	}
}

